mapper.select:
SELECT rf.file_id, rf.room_id, rf.uploader_id, rf.uploader_nickname, rf.file_name, rf.file_path, rf.file_size, rf.thumbnail_size, rf.file_type, rf.content_type, rf.download_count, rf.upload_time, rf.create_time, rf.update_time, r.room_name FROM room_file rf LEFT JOIN room r ON rf.room_id = r.room_id
AND rf.room_id = #{query.roomId}
AND rf.uploader_id = #{query.uploaderId}
AND rf.file_type = #{query.fileType}
AND rf.upload_time >= #{query.startTime}
AND rf.upload_time <= #{query.endTime}
AND rf.file_name LIKE CONCAT('%', #{query.keyword}, '%')
ORDER BY rf.upload_time DESC
